module top_module(J,K,clk_inv,rst,q);input J,K,clk_inv,rst;
output q;
reg q;
always @(posedge clk_inv) begin
	if (J==1 & K==1) begin
		q<=~q; 

	end
	else if (J==1 & K==0) begin
		q<=1; 
	end
	else if(J==0 & K==1) begin
		q<=0; 
	end
	else if(J==0 & K==0) begin
		q<=q; 
	end
end
always @(posedge rst) begin
	q <= 0;
end
endmodule
